156→/* CSR NDS_MCACHE_CTL */
157→#define DC_WARND_MSK                            (0x3 << 13)
158→#define DC_COHEN_MSK                            (0x1 << 19)
159→#define DC_COHSTA_MSK                           (0x1 << 20)
160→
161→/* CSR NDS_DCM_CFG */
162→#define DSET_MSK                                ((1ULL << 2) | (1ULL << 1) | (1ULL << 0))
163→#define DWAY_MSK                                ((1ULL << 5) | (1ULL << 4) | (1ULL << 3))
164→#define DSIZE_MSK                               ((1ULL << 8) | (1ULL << 7) | (1ULL << 6))
165→
166→/* SMU.SYSTEMCFG Configuration Register */
167→#define L2C_CTL_OFF                             8
168→#define L2C_CTL_MSK                             (0x1 << L2C_CTL_OFF)
169→
170→/* Configuration Register */
171→#define L2C_SIZE_OFF                            7
172→#define L2C_SIZE_MSK                            (0x1F << L2C_SIZE_OFF)
173→#define L2C_SIZE_0KB                            (0x00 << L2C_SIZE_OFF)
174→#define L2C_SIZE_128KB                          (0x01 << L2C_SIZE_OFF)
175→#define L2C_SIZE_256KB                          (0x02 << L2C_SIZE_OFF)
176→#define L2C_SIZE_512KB                          (0x04 << L2C_SIZE_OFF)
177→#define L2C_SIZE_1024KB                         (0x08 << L2C_SIZE_OFF)
178→#define L2C_SIZE_2048KB                         (0x10 << L2C_SIZE_OFF)
179→#define L2C_LINE_SIZE                           32
180→
181→/* L2 cache version */
182→#define L2C_VERSION_OFF                         24
183→#define L2C_VERSION_MSK                         (0xFF << L2C_VERSION_OFF)
184→
185→/* Control Register */
186→#define L2C_ENABLE                              (0x1 << 0)
187→#define L2C_IPFDPT                              (0x3 << 3)
188→#define L2C_DPFDPT                              (0x3 << 5)
189→
190→void enable_l2c()
191→{
192→    unsigned int /*iset, iway, isize, dset, dway,*/ dsize;
193→    unsigned long /*icm_cfg = 0,*/ dcm_cfg = 0;
194→    unsigned int l2c_size = 0;
195→
196→	/* Enable I/D cache HW prefetcher and D-cache write-around (threshold: 4 cache lines) as default */
197→    __nds__csrrc(DC_WARND_MSK, NDS_MCACHE_CTL);
198→    __nds__csrrs((0x1 << 13) | (0x1 << 10) | (0x1 << 9), NDS_MCACHE_CTL);
199→
200→    l2c_size = 0;
201→    if (DEV_SMU->SYSTEMCFG & L2C_CTL_MSK)
202→    {
203→        printf("CPU supports L2C cache\n");
204→
205→        if ((DEV_L2C->CFG & L2C_SIZE_MSK) >> L2C_SIZE_OFF)
206→        {
207→            l2c_size = (unsigned int)(((DEV_L2C->CFG & L2C_SIZE_MSK) >> L2C_SIZE_OFF) * 128);
208→        }
209→        printf("The L2C cache size = %uKB\n", l2c_size);
210→
211→        if (((DEV_L2C->CFG & L2C_VERSION_MSK) >> L2C_VERSION_OFF) >= 16)
212→        {
213→            /* In Gen2, cache coherence should be enabled before L1 cache enabled.*/
214→            __nds__csrrs(DC_COHEN_MSK, NDS_MCACHE_CTL);
215→            while((__nds__csrr(NDS_MCACHE_CTL) & DC_COHSTA_MSK) == 0);
216→        }
217→
218→        /* Enable L2C Cache */
219→        DEV_L2C->CTL |= L2C_ENABLE;
220→
221→        /* Enable L2C prefetch */
222→        DEV_L2C->CTL |= L2C_IPFDPT;
223→        DEV_L2C->CTL |= L2C_DPFDPT;
224→    }
225→    else
226→    {
227→        printf("CPU does NOT support L2C cache\n");
228→    }
229→
230→
231→    dcm_cfg = __nds__csrr(NDS_MDCM_CFG);
232→    if (((dcm_cfg & DSIZE_MSK) >> 6) && (((dcm_cfg & DSIZE_MSK) >> 6) <= 5))
233→    {
234→        dsize = (unsigned int)(1 << (((dcm_cfg & DSIZE_MSK) >> 6) + 2));
235→    }
236→    else if (((dcm_cfg & DSIZE_MSK) >> 6) >= 6)
237→    {
238→        printf("Warning L1C d cacheline size is reserved value\n");
239→        dsize = 0;
240→    }
241→    else
242→    {
243→        dsize = 0;
244→    }
245→
246→    printf("The L1C DCache line size = %u\n", dsize);
247→    if (dsize == 0)
248→    {
249→        printf("This CPU doesn't have L1C DCache.\n");
250→        return ;
251→    }
252→    else
253→    {
254→        /* Enable L1C DCache */
255→        __nds__csrrs((0x1 << 1), NDS_MCACHE_CTL);
256→    }
257→}
