274→void static inline _startPFM()
275→{
276→#if defined(__riscv)
277→    //inhibit all machine counters
278→    __nds__mtsr(0X7F, NDS_MCOUNTINHIBIT);
279→
280→    //reset counters
281→#if (__riscv_xlen == 32)    // for RV32
282→    __nds__mtsr(0, NDS_MINSTRET);
283→    __nds__mtsr(0, NDS_MINSTRETH);
284→    __nds__mtsr(0, NDS_MCYCLE);
285→    __nds__mtsr(0, NDS_MCYCLEH);
286→#else   // for RV64
287→    __nds__mtsr(0, NDS_MINSTRET);
288→    __nds__mtsr(0, NDS_MCYCLE);
289→#endif
290→
291→#ifdef ENA_CACHE_PFM
292→    //set performance event
293→    __nds__mtsr(0x61, NDS_MHPMEVENT3);
294→    __nds__mtsr(0x71, NDS_MHPMEVENT4);
295→    __nds__mtsr(0xc1, NDS_MHPMEVENT5);
296→    __nds__mtsr(0x91, NDS_MHPMEVENT6);
297→    //reset counters
298→    __nds__mtsr(0, NDS_MHPMCOUNTER3);
299→    __nds__mtsr(0, NDS_MHPMCOUNTER4);
300→    __nds__mtsr(0, NDS_MHPMCOUNTER5);
301→    __nds__mtsr(0, NDS_MHPMCOUNTER6);
302→#endif
303→
304→#ifdef ENA_L2C_PFM
305→    init_l2c_hpm();
306→#endif
307→
308→    //enable all machine counters
309→    __nds__mtsr(0, NDS_MCOUNTINHIBIT);
310→#else   // for V3
311→    __nds32__mtsr(0, NDS32_SR_PFMC0);
312→    __nds32__mtsr(0, NDS32_SR_PFMC1);
313→    __nds32__mtsr(0, NDS32_SR_PFMC2);
314→    __nds32__mtsr(0x1000B, NDS32_SR_PFM_CTL);
315→#endif
316→}
317→
318→void static inline _stopPFM()
319→{
320→#ifdef __riscv
321→    //inhibit all machine counters
322→    __nds__mtsr(0X7F, NDS_MCOUNTINHIBIT);
323→
324→    //get performance counters
325→#if (__riscv_xlen == 32)    // for RV32
326→    stopInst_L  = __nds__mfsr(NDS_MINSTRET);
327→    stopInst_H  = __nds__mfsr(NDS_MINSTRETH);
328→    stopCycle_L = __nds__mfsr(NDS_MCYCLE);
329→    stopCycle_H = __nds__mfsr(NDS_MCYCLEH);
330→    inst  = (uint64_t)stopInst_H << 32 | stopInst_L;
331→    cycle = (uint64_t)stopCycle_H << 32 | stopCycle_L;
332→#else   // for RV64
333→    inst  = __nds__mfsr(NDS_MINSTRET);
334→    cycle = __nds__mfsr(NDS_MCYCLE);
335→#endif
336→
337→    //check the counter overflow status
338→    long mmsc_cfg_pmnds = __nds__mfsr(NDS_MMSC_CFG) & 0x8000;
339→    if (mmsc_cfg_pmnds != 0)
340→    {
341→        long mcounterovf = __nds__mfsr(NDS_MCOUNTEROVF);
342→        if(mcounterovf & 0x4)
343→            printf("Warning! The instruction counter overflows!!!\n");
344→        if(mcounterovf & 0x1)
345→            printf("Warning! The cycle counter overflows!!!\n");
346→    }
347→
348→#ifdef ENA_CACHE_PFM
349→    //get cache pfm counters
350→    dcache_load_access = __nds__mfsr(NDS_MHPMCOUNTER3);
351→    dcache_load_miss = __nds__mfsr(NDS_MHPMCOUNTER4);
352→    dcache_store_miss = __nds__mfsr(NDS_MHPMCOUNTER6);
353→    data_cache_stall_cycle = __nds__mfsr(NDS_MHPMCOUNTER5);
354→#endif
355→
356→#ifdef ENA_L2C_PFM
357→    get_l2c_hpm();
358→#endif
359→
360→    //enable all machine counters
361→    __nds__mtsr(0, NDS_MCOUNTINHIBIT);
362→#else   // for V3
363→    __nds32__mtsr(0x10008, NDS32_SR_PFM_CTL);
364→    if (__nds32__mfsr(NDS32_SR_PFM_CTL) & (7UL << 6))
365→        printf("\n!!!Error! PFM has OVERFLOWED! PFM_CTL=0x%08X\n\n", (int)__nds32__mfsr(NDS32_SR_PFM_CTL));
366→    __nds32__dsb();
367→    cycle = __nds32__mfsr(NDS32_SR_PFMC0);
368→    inst = __nds32__mfsr(NDS32_SR_PFMC1);
369→#endif
370→}
