264→#ifdef __riscv_zfh
265→uint32_t verify_buffer_f16(void *outBuf, void *goldenBuf, uint32_t length, float snrThreshold)
266→{
267→    union data
268→    {
269→        _Float16 f16;
270→        unsigned short i16;
271→    };
272→    precisionAnalysis myPrecision = { .maxAbsDiff = 0, .snr = 0};
273→
274→    unsigned int i;
275→    double sumSquareErr = 0.0f, squareGloden = 0.0f;
276→    float maxAbsDiff = 0.0f;
277→    _Float16 *outPtr = outBuf;
278→    _Float16 *goldenPtr= goldenBuf;
279→    unsigned max_diff_idx = 0;
280→
281→    // find the max absolute diff
282→    for(i=0; i<length; i++)
283→    {
284→        float diff = fabs(goldenPtr[i] - outPtr[i]);
285→        if(diff > maxAbsDiff)
286→        {
287→            maxAbsDiff = diff;
288→            max_diff_idx = i;
289→        }
290→        sumSquareErr += (double)diff * diff;
291→        squareGloden += (double)goldenPtr[i] * goldenPtr[i];
292→
293→        if(diff > 0.0f)
294→        {
295→#ifdef DEBUG_MODE
296→            union data out, golden;
297→            out.f16 = outPtr[i];
298→            golden.f16 = goldenPtr[i];
299→            DBG_MSG("out[%u]=%04x (%+f), golden[%u]=%04x (%+f)\n", i, out.i16, (float)out.f16, i, golden.i16, (float)golden.f16);
300→#endif
301→        }
302→    }
303→
304→    // calculate the SNR
305→    myPrecision.maxAbsDiff = maxAbsDiff;
306→    if(sumSquareErr == 0.0f)
307→    {
308→        myPrecision.snr = ERROR_EQ_ZERO;
309→    }
310→    else
311→    {
312→        myPrecision.snr = 10 * log10f(squareGloden / sumSquareErr);
313→    }
314→
315→    // show the accuracy checking results
316→    uint32_t retStatus;
317→    if((sumSquareErr == 0.0f) || ((myPrecision.snr >= snrThreshold) && (snrThreshold != ERROR_EQ_ZERO)))
318→    {
319→        printf("accuracy checking pass\n\n");
320→        retStatus = NDS_SUCCESS;
321→    }
322→    else
323→    {
324→        printf("max_abs_diff=%5.10f, SNR=%5.10f max_diff_idx=%u\n", myPrecision.maxAbsDiff, myPrecision.snr, max_diff_idx);
325→        printf("accuracy checking fail\n\n");
326→        retStatus = NDS_FAILURE;
327→    }
328→
329→    return retStatus;
330→}
