 92→	__I  unsigned int SYSTEMCFG;            /* 0x08 SYSTEM configuration register */
 93→	__I  unsigned int SMUVER;               /* 0x0C SMU version register */
 94→	__IO unsigned int WRSR;                 /* 0x10 Wakeup and Reset Status Register */
 95→	__IO unsigned int SMUCR;                /* 0x14 SMU Command Register */
 96→	     unsigned int RESERVED1[1];         /* 0x18 Reserved */
 97→	__IO unsigned int WRMASK;               /* 0x1C Wake up Mask Register */
 98→	__IO unsigned int CER;                  /* 0x20 Clock Enable Register */
 99→	__IO unsigned int CRR;                  /* 0x24 Clock Ratio Register */
100→	     unsigned int RESERVED2[6];         /* 0x28 ~ 0x3C Reserved Register */
101→	__IO unsigned int SCRATCH;              /* 0x40 Scratch Register */
102→	     unsigned int RESERVED3[3];         /* 0x44 ~ 0x4C Reserved */
103→	__IO unsigned int RESET_VECTOR;         /* 0x50 CPU Reset Vector Register */
104→} SMU_RegDef;
