148→// #define SMU_BASE                _IO_(0xF0100000)
149→#define SMU_BASE                (0xF0100000)
150→#define L2C_BASE                (0xE0500000)
151→#define AE350_SMU               ((SMU_RegDef *)  SMU_BASE)
152→#define AE350_L2C               ((L2C_RegDef *)  L2C_BASE)
153→#define DEV_SMU              AE350_SMU
154→#define DEV_L2C              AE350_L2C
