 ***************************************************************************/

#include <stdio.h>
// #include "nds32_math_types.h"
#include "nds_math_types.h"
#include <inttypes.h>

#ifdef PF_COUNTER
#include <nds32_intrinsic.h>

//Global instruction and cycle
#ifdef USE_EXTERN
#ifdef __riscv
    extern uint64_t inst;
    extern uint64_t cycle;

    extern uint64_t startInst;
    extern uint64_t startCycle;
    extern uint64_t stopInst;
    extern uint64_t stopCycle;
#if __riscv_xlen == 32
    extern uint32_t startInst_L;
    extern uint32_t startInst_H;
    extern uint32_t startCycle_L;
    extern uint32_t startCycle_H;
    extern uint32_t stopInst_L;
    extern uint32_t stopInst_H;
    extern uint32_t stopCycle_L;
    extern uint32_t stopCycle_H;
#endif
#else
    extern unsigned int inst;
    extern unsigned int cycle;
#endif
#else
#ifdef __riscv
    uint64_t inst;
    uint64_t cycle;

    uint64_t startInst;
    uint64_t startCycle;
    uint64_t stopInst;
    uint64_t stopCycle;
#if __riscv_xlen == 32
    uint32_t startInst_L;
    uint32_t startInst_H;
    uint32_t startCycle_L;
    uint32_t startCycle_H;
    uint32_t stopInst_L;
    uint32_t stopInst_H;
    uint32_t stopCycle_L;
    uint32_t stopCycle_H;
#endif
#else
    unsigned int inst;
    unsigned int cycle;
#endif
#endif

#ifdef ENA_CACHE_PFM
unsigned long dcache_load_access,
            dcache_load_miss,
            dcache_store_miss,
            data_cache_stall_cycle;
#endif

#ifdef ENA_L2C_PFM
unsigned long l2c_access,
            l2c_miss;
#endif

#ifdef ENA_L2C_PFM
//----- difinitions for L2C_begin -----
#define __I                     volatile const	/* 'read only' permissions      */
#define __O                     volatile        /* 'write only' permissions     */
#define __IO                    volatile        /* 'read / write' permissions   */

/*****************************************************************************
 * SMU - AE350
 ****************************************************************************/
typedef struct {
	__I  unsigned int SYSTEMVER;            /* 0x00 SYSTEM ID and Revision Register */
	     unsigned int RESERVED0[1];         /* 0x04 Reserved */
	__I  unsigned int SYSTEMCFG;            /* 0x08 SYSTEM configuration register */
	__I  unsigned int SMUVER;               /* 0x0C SMU version register */
	__IO unsigned int WRSR;                 /* 0x10 Wakeup and Reset Status Register */
	__IO unsigned int SMUCR;                /* 0x14 SMU Command Register */
	     unsigned int RESERVED1[1];         /* 0x18 Reserved */
	__IO unsigned int WRMASK;               /* 0x1C Wake up Mask Register */
	__IO unsigned int CER;                  /* 0x20 Clock Enable Register */
	__IO unsigned int CRR;                  /* 0x24 Clock Ratio Register */
	     unsigned int RESERVED2[6];         /* 0x28 ~ 0x3C Reserved Register */
	__IO unsigned int SCRATCH;              /* 0x40 Scratch Register */
	     unsigned int RESERVED3[3];         /* 0x44 ~ 0x4C Reserved */
	__IO unsigned int RESET_VECTOR;         /* 0x50 CPU Reset Vector Register */
} SMU_RegDef;

/*****************************************************************************
 * L2CACHE - AE350
 ****************************************************************************/
typedef struct {
	__I  unsigned long long CFG;            /* 0x00 Configuration Register */
	__IO unsigned long long CTL;            /* 0x08 Control Register */
	__IO unsigned long long HPMCTL0;        /* 0x10 HPM Control Register0 */
	__IO unsigned long long HPMCTL1;        /* 0x18 HPM Control Register1 */
	__IO unsigned long long HPMCTL2;        /* 0x20 HPM Control Register2 */
	__IO unsigned long long HPMCTL3;        /* 0x28 HPM Control Register3 */
	__IO unsigned long long ASYNERR;        /* 0x30 Asynchronous Error Register */
	__IO unsigned long long ERR;            /* 0x38 Error Register */
	union {
		struct {
			__IO unsigned long long CORE0CCTLCMD;   /* 0x40 Core 0 CCTL Command Register */
			__IO unsigned long long CORE0CCTLACC;   /* 0x48 Core 0 CCTL Access Line Register */
			__IO unsigned long long CORE1CCTLCMD;   /* 0x50 Core 1 CCTL Command Register */
			__IO unsigned long long CORE1CCTLACC;   /* 0x58 Core 1 CCTL Access Line Register */
			__IO unsigned long long CORE2CCTLCMD;   /* 0x60 Core 2 CCTL Command Register */
			__IO unsigned long long CORE2CCTLACC;   /* 0x68 Core 2 CCTL Access Line Register */
			__IO unsigned long long CORE3CCTLCMD;   /* 0x70 Core 3 CCTL Command Register */
			__IO unsigned long long CORE3CCTLACC;   /* 0x78 Core 3 CCTL Access Line Register */
			__I  unsigned long long CCTLSTATUS;     /* 0x80 CCTL Status Register */
			     unsigned long long RESERVED0;      /* 0x88 Reserved */
			__IO unsigned long long TGTWDATA[4];    /* 0x90 ~ 0xAF TGT Write Data 0 to 3 */
			__I  unsigned long long TGTRDATA[4];    /* 0xB0 ~ 0xCF TGT Read Data 0 to 3 */
			__IO unsigned long long TGTWECC;        /* 0xD0 TGT Write ECC Code Register */
			__I  unsigned long long TGTRECC;        /* 0xD8 TGT Read ECC Code Register */
			     unsigned long long RESERVED1[36];  /* 0xE0 ~ 0x1FF Reserved */
			__IO unsigned long long HPMCNT[32];     /* 0x200 ~ 0x2F8 HPM Counter Register 0 to 31 */
			__I  unsigned long long WAYMASK[16];    /* 0x300 ~ 0x378 Way Allocation Mask Register 0 to 15 */
		} REG;
		struct {
			__IO unsigned long long CCTLCMD;        /* 0x40 Core 0 CCTL Command Register */
			__IO unsigned long long CCTLACC;        /* 0x48 Core 0 CCTL Access Line Register */
			     unsigned long long RESERVED0[6];   /* 0x50 ~ 0x7F Reserved */
			__I  unsigned long long CCTLSTATUS;     /* 0x80 Core 0 CCTL Status Register */
			     unsigned long long RESERVED[503];  /* 0x88 Reserved */
		} CORECCTL[8];
	};
} L2C_RegDef;

// #define SMU_BASE                _IO_(0xF0100000)
#define SMU_BASE                (0xF0100000)
#define L2C_BASE                (0xE0500000)
#define AE350_SMU               ((SMU_RegDef *)  SMU_BASE)
#define AE350_L2C               ((L2C_RegDef *)  L2C_BASE)
#define DEV_SMU              AE350_SMU
#define DEV_L2C              AE350_L2C

/* CSR NDS_MCACHE_CTL */
#define DC_WARND_MSK                            (0x3 << 13)
#define DC_COHEN_MSK                            (0x1 << 19)
#define DC_COHSTA_MSK                           (0x1 << 20)

/* CSR NDS_DCM_CFG */
#define DSET_MSK                                ((1ULL << 2) | (1ULL << 1) | (1ULL << 0))
#define DWAY_MSK                                ((1ULL << 5) | (1ULL << 4) | (1ULL << 3))
#define DSIZE_MSK                               ((1ULL << 8) | (1ULL << 7) | (1ULL << 6))

/* SMU.SYSTEMCFG Configuration Register */
#define L2C_CTL_OFF                             8
#define L2C_CTL_MSK                             (0x1 << L2C_CTL_OFF)

/* Configuration Register */
#define L2C_SIZE_OFF                            7
#define L2C_SIZE_MSK                            (0x1F << L2C_SIZE_OFF)
#define L2C_SIZE_0KB                            (0x00 << L2C_SIZE_OFF)
#define L2C_SIZE_128KB                          (0x01 << L2C_SIZE_OFF)
#define L2C_SIZE_256KB                          (0x02 << L2C_SIZE_OFF)
#define L2C_SIZE_512KB                          (0x04 << L2C_SIZE_OFF)
#define L2C_SIZE_1024KB                         (0x08 << L2C_SIZE_OFF)
#define L2C_SIZE_2048KB                         (0x10 << L2C_SIZE_OFF)
#define L2C_LINE_SIZE                           32

/* L2 cache version */
#define L2C_VERSION_OFF                         24
#define L2C_VERSION_MSK                         (0xFF << L2C_VERSION_OFF)

/* Control Register */
#define L2C_ENABLE                              (0x1 << 0)
#define L2C_IPFDPT                              (0x3 << 3)
#define L2C_DPFDPT                              (0x3 << 5)

void enable_l2c()
{
    unsigned int /*iset, iway, isize, dset, dway,*/ dsize;
    unsigned long /*icm_cfg = 0,*/ dcm_cfg = 0;
    unsigned int l2c_size = 0;

	/* Enable I/D cache HW prefetcher and D-cache write-around (threshold: 4 cache lines) as default */
    __nds__csrrc(DC_WARND_MSK, NDS_MCACHE_CTL);
    __nds__csrrs((0x1 << 13) | (0x1 << 10) | (0x1 << 9), NDS_MCACHE_CTL);

    l2c_size = 0;
    if (DEV_SMU->SYSTEMCFG & L2C_CTL_MSK)
    {
        printf("CPU supports L2C cache\n");

        if ((DEV_L2C->CFG & L2C_SIZE_MSK) >> L2C_SIZE_OFF)
        {
            l2c_size = (unsigned int)(((DEV_L2C->CFG & L2C_SIZE_MSK) >> L2C_SIZE_OFF) * 128);
        }
        printf("The L2C cache size = %uKB\n", l2c_size);

        if (((DEV_L2C->CFG & L2C_VERSION_MSK) >> L2C_VERSION_OFF) >= 16)
        {
            /* In Gen2, cache coherence should be enabled before L1 cache enabled.*/
            __nds__csrrs(DC_COHEN_MSK, NDS_MCACHE_CTL);
            while((__nds__csrr(NDS_MCACHE_CTL) & DC_COHSTA_MSK) == 0);
        }

        /* Enable L2C Cache */
        DEV_L2C->CTL |= L2C_ENABLE;

        /* Enable L2C prefetch */
        DEV_L2C->CTL |= L2C_IPFDPT;
        DEV_L2C->CTL |= L2C_DPFDPT;
    }
    else
    {
        printf("CPU does NOT support L2C cache\n");
    }


    dcm_cfg = __nds__csrr(NDS_MDCM_CFG);
    if (((dcm_cfg & DSIZE_MSK) >> 6) && (((dcm_cfg & DSIZE_MSK) >> 6) <= 5))
    {
        dsize = (unsigned int)(1 << (((dcm_cfg & DSIZE_MSK) >> 6) + 2));
    }
    else if (((dcm_cfg & DSIZE_MSK) >> 6) >= 6)
    {
        printf("Warning L1C d cacheline size is reserved value\n");
        dsize = 0;
    }
    else
    {
        dsize = 0;
    }

    printf("The L1C DCache line size = %u\n", dsize);
    if (dsize == 0)
    {
        printf("This CPU doesn't have L1C DCache.\n");
        return ;
    }
    else
    {
        /* Enable L1C DCache */
        __nds__csrrs((0x1 << 1), NDS_MCACHE_CTL);
    }
}

void init_l2c_hpm()
{
    DEV_L2C->HPMCTL0 = 0x201;
    DEV_L2C->REG.HPMCNT[0] = 0;
    DEV_L2C->REG.HPMCNT[1] = 0;
}

void get_l2c_hpm()
{
    l2c_access = DEV_L2C->REG.HPMCNT[0];
    l2c_miss = DEV_L2C->REG.HPMCNT[1];
}
//----- difinitions for L2C_end -----
#endif

void static inline _startPFM()
{
#if defined(__riscv)
    //inhibit all machine counters
    __nds__mtsr(0X7F, NDS_MCOUNTINHIBIT);

    //reset counters
#if (__riscv_xlen == 32)    // for RV32
    __nds__mtsr(0, NDS_MINSTRET);
    __nds__mtsr(0, NDS_MINSTRETH);
    __nds__mtsr(0, NDS_MCYCLE);
    __nds__mtsr(0, NDS_MCYCLEH);
#else   // for RV64
    __nds__mtsr(0, NDS_MINSTRET);
    __nds__mtsr(0, NDS_MCYCLE);
#endif

#ifdef ENA_CACHE_PFM
    //set performance event
    __nds__mtsr(0x61, NDS_MHPMEVENT3);
    __nds__mtsr(0x71, NDS_MHPMEVENT4);
    __nds__mtsr(0xc1, NDS_MHPMEVENT5);
    __nds__mtsr(0x91, NDS_MHPMEVENT6);
    //reset counters
    __nds__mtsr(0, NDS_MHPMCOUNTER3);
    __nds__mtsr(0, NDS_MHPMCOUNTER4);
    __nds__mtsr(0, NDS_MHPMCOUNTER5);
    __nds__mtsr(0, NDS_MHPMCOUNTER6);
#endif

#ifdef ENA_L2C_PFM
    init_l2c_hpm();
#endif

    //enable all machine counters
    __nds__mtsr(0, NDS_MCOUNTINHIBIT);
#else   // for V3
    __nds32__mtsr(0, NDS32_SR_PFMC0);
    __nds32__mtsr(0, NDS32_SR_PFMC1);
    __nds32__mtsr(0, NDS32_SR_PFMC2);
    __nds32__mtsr(0x1000B, NDS32_SR_PFM_CTL);
#endif
}

void static inline _stopPFM()
{
#ifdef __riscv
    //inhibit all machine counters
    __nds__mtsr(0X7F, NDS_MCOUNTINHIBIT);

    //get performance counters
#if (__riscv_xlen == 32)    // for RV32
    stopInst_L  = __nds__mfsr(NDS_MINSTRET);
    stopInst_H  = __nds__mfsr(NDS_MINSTRETH);
    stopCycle_L = __nds__mfsr(NDS_MCYCLE);
    stopCycle_H = __nds__mfsr(NDS_MCYCLEH);
    inst  = (uint64_t)stopInst_H << 32 | stopInst_L;
    cycle = (uint64_t)stopCycle_H << 32 | stopCycle_L;
#else   // for RV64
    inst  = __nds__mfsr(NDS_MINSTRET);
    cycle = __nds__mfsr(NDS_MCYCLE);
#endif

    //check the counter overflow status
    long mmsc_cfg_pmnds = __nds__mfsr(NDS_MMSC_CFG) & 0x8000;
    if (mmsc_cfg_pmnds != 0)
    {
        long mcounterovf = __nds__mfsr(NDS_MCOUNTEROVF);
        if(mcounterovf & 0x4)
            printf("Warning! The instruction counter overflows!!!\n");
        if(mcounterovf & 0x1)
            printf("Warning! The cycle counter overflows!!!\n");
    }

#ifdef ENA_CACHE_PFM
    //get cache pfm counters
    dcache_load_access = __nds__mfsr(NDS_MHPMCOUNTER3);
    dcache_load_miss = __nds__mfsr(NDS_MHPMCOUNTER4);
    dcache_store_miss = __nds__mfsr(NDS_MHPMCOUNTER6);
    data_cache_stall_cycle = __nds__mfsr(NDS_MHPMCOUNTER5);
#endif

#ifdef ENA_L2C_PFM
    get_l2c_hpm();
#endif

    //enable all machine counters
    __nds__mtsr(0, NDS_MCOUNTINHIBIT);
#else   // for V3
    __nds32__mtsr(0x10008, NDS32_SR_PFM_CTL);
    if (__nds32__mfsr(NDS32_SR_PFM_CTL) & (7UL << 6))
        printf("\n!!!Error! PFM has OVERFLOWED! PFM_CTL=0x%08X\n\n", (int)__nds32__mfsr(NDS32_SR_PFM_CTL));
    __nds32__dsb();
    cycle = __nds32__mfsr(NDS32_SR_PFMC0);
    inst = __nds32__mfsr(NDS32_SR_PFMC1);
#endif
}

#define startPFM _startPFM();
#define stopPFM  _stopPFM();

