    float32_t  mhzbycycle = (float32_t) ONEMHZ / (result->cycle) * 100.0f;
    printf("The MHZ per cycle count is %5.2f%%\n", mhzbycycle);
#endif
}
#endif  //DISABLE_PFCOUNTER_FUNCTION

