#include <stdio.h>
#include "riscv_nn_activation.h"
#include "test_util.h"
#ifdef PF_COUNTER
#include "nds_pfcounter.h"
#endif
#ifdef ENA_VERIFY_CMSIS_NN_WRAPPER
#include "convert_between_andes_nn_and_cmsis_nn.h"
#endif

int test(char* fname_inOut,
         char* fname_golden,
         uint32_t size,
         uint16_t int_bits,
         riscv_nn_activation_fun act_fun)
{
    {
        char act_fun_str[32];
        if (act_fun == NN_SIGMOID)
        {
            strcpy(act_fun_str, "act_fun=NN_SIGMOID");
        }
        else
        {
            strcpy(act_fun_str, "act_fun=NN_TANH");
        }
        dump_param("size=%" PRIu32 ";int_bits=%" PRIi16 ";%s", size, int_bits, act_fun_str);
    }

    FILE *fptr_in_out, *fptr_golden;
    //backup originally malloced starting address for later memory releasing
    void *in_out_ori, *golden_ori;

    q15_t *in_out = (q15_t*)test_malloc(sizeof(q15_t) * size, "in_out", &in_out_ori);
    q15_t *golden = (q15_t*)test_malloc(sizeof(q15_t) * size, "golden", &golden_ori);

    test_Fopen(fname_inOut, "rb", &fptr_in_out);
    test_Fread(in_out, sizeof(*in_out), size, fptr_in_out, "in_out");
#ifdef ENA_RUN_TWICE
    void *in_out2_ori;
    q15_t *in_out2 = (q15_t*)test_malloc(sizeof(q15_t) * size, "in_out2", &in_out2_ori);
    for (size_t i = 0; i < size; i++)
    {
        in_out2[i] = in_out[i];
    }
#endif
    process_after_reading_input_data();

#ifdef ENA_RUN_TWICE
    riscv_nn_activate_s16(in_out2, size, int_bits, act_fun);
#endif

    process_before_perf_measuring();
#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_activate_s16(in_out, size, int_bits, act_fun);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if ENA_DUMP_GOLDEN
    test_Fopen(fname_golden, "wb+", &fptr_golden);
    fwrite(in_out, sizeof(*golden), size, fptr_golden);
    uint32_t retStatus = NDS_SUCCESS;
#else
    test_Fopen(fname_golden, "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), size, fptr_golden, "golden");
    uint32_t retStatus = verify_buffer(in_out, golden, size, sizeof(*in_out), 0);
#endif

    test_free(&in_out_ori);
    test_free(&golden_ori);
#ifdef ENA_RUN_TWICE
    test_free(&in_out2_ori);
#endif
    fclose(fptr_in_out);
    fclose(fptr_golden);

