#!/usr/bin/expect

# Set some variables

# Setup the timeout value while simulating each test case on real board.
# This value should be replaced by build system or manually changed.
#   e.g. "set timeout 500"
set timeout 600

# Setup the nds32 gdb full-path so that we can execute it to connect to aice.
# This value should be replaced by build system or manually changed.
#   e.g. "set gdb /path/to/nds32le-elf-newlib-v3/bin/nds32le-elf-gdb"
set gdb riscv64-elf-gdb

# Setup the host machine that iceman is running on.
# This value should be replaced by build system or manually changed.
#   e.g. "set host apc188"
set host $::env(MYPC)

#Setup the port opened by iceman connecting to real board.
# This value should be replaced by build system or manually changed.
#   e.g. "set port 1234"
set port $::env(MYPORT)

send "set pagination off\n"

set elf [lindex $argv 0]
set gcc [lindex $argv 1]
set cache [lindex $argv 2]
set reset [lindex $argv 3]
set hvm_pma [lindex $argv 4]
set ddr_latency [lindex $argv 5]
set non_blocking_load [lindex $argv 6]
set dc_wa_threshold [lindex $argv 7]
set stdin [lindex $argv 8]
set gdb_prompt_pattern ".*gdb\[)] "

set fail_ret 1

# Execute binary
if { $gcc == "yes" } {
  spawn $gdb -e "$elf"
} else {
  spawn $gdb -e "$elf" -return-child-result -q
}

# When timeout, will send contrlC to stop this program
proc ctrlC {} {
	send \003
	set status 123
	send "quit\n"
	expect {
		"Quit anyway?" {
			send "y\n"
		}
	}
	expect eof
	exit $status
}

proc cache_on {} {
    send_user "Start to setup L2C.\n"
	l2c_on
	send_user "Setup L2C done.\n"

    send_user "Start to enable I/D cache, I/D cache prefetch and D cache coherence.\n"
	enable_cache "603"
	expect gdb { send_user "Enable I/D cache, I/D cache prefetch  and D cache coherence done.\n" }
}

proc l2c_on {} {
    #addr of SMU.SYSTEMCFG
    set smu_system_cfg_addr [format %x [expr {0xF0100008} ] ]
    set smu_system_cfg_val [ get_mem_value "$smu_system_cfg_addr" ]

    #SMU.SYSTEMCFG.L2C
    set l2c_ctl_offset 7
    set l2c_ctl_mask [format %x [expr {0x100} ] ]

    set is_l2c_supported [format %d [expr ($smu_system_cfg_val & 0x$l2c_ctl_mask) ] ]
    if {$is_l2c_supported} {
        send_user "CPU supports L2C cache.\n"

        # addr of L2C configuration register
        set l2c_cfg_addr [format %x [expr {0xE0500000} ] ]
        set l2c_cfg_val [ get_mem_value "$l2c_cfg_addr" ]
        set l2c_ver_off 24
        set l2c_ver_mask [expr 0xff << $l2c_ver_off]
        set l2c_ctl_addr [format %x [expr {0xE0500008} ] ]
        set l2c_ipfdpt_mask [expr 0x3 << 3]
        set l2c_dpfdpt_mask [expr 0x3 << 5]
        set dc_cohen_mask [expr 0x1 << 19]
        set dc_cohsta_mask [expr 0x1 << 20]

        set l2c_ver [expr [expr $l2c_cfg_val & $l2c_ver_mask] >> $l2c_ver_off ]
        if {$l2c_ver >= 16} {
            # In Gen2, cache coherence should be enabled before L1 cache enabled.
            send "set (long)\$mcache_ctl |= $dc_cohen_mask\n"
            expect gdb { send_user "Enable data cache to participate in the coherence management.\n" }
            send "p/x \$mcache_ctl\n"

            while { [expr [ get_reg_value "mcache_ctl" ] & $dc_cohsta_mask == 0] } {
                sleep 1
            }
        }

        # Enable L2C Cache (this is optional, the L2C is enabled by default)
        send "set \*0x$l2c_ctl_addr |= 1\n"
        expect gdb { send_user "Enable L2C done.\n" }

        # Set L2 instruction prefetch to 3 requests
        send "set \*0x$l2c_ctl_addr |= $l2c_ipfdpt_mask\n"
        expect gdb { send_user "Enable L2 instruction prefetch done.\n" }

        # Set L2 data prefetch to 8 requests
        send "set \*0x$l2c_ctl_addr |= $l2c_dpfdpt_mask\n"
        expect gdb { send_user "Enable L2 data prefetch done.\n" }
    } else {
        send_user "CPU does NOT support L2C cache\n"
    }
}

proc lm_on {} {
    send_user "Start to enable_localmemory: ILM.\n"
    enable_ilm

    send_user "Start to enable_localmemory: DLM.\n"
    enable_dlm
}

# Get the value in memory
proc get_mem_value { addr } {
	global gdb_prompt_pattern

    send "p/x (long)\*0x$addr\n"
    expect {
		-re "= (0x\[0-9a-fA-F]+)$gdb_prompt_pattern" {
			set mem_value $expect_out(1,string)
		}
    }
    return $mem_value
}

# Get register's value
proc get_reg_value { x } {
	global gdb_prompt_pattern

	send "p/x (long)\$$x\n"
	expect {
		-re "(0x\[0-9a-fA-F]+)$gdb_prompt_pattern" {
			set reg_value $expect_out(1,string)
		}
	}
	return $reg_value
}

# Enable Icache or Dcache
proc enable_cache { x } {
	send "set (long)\$mcache_ctl |= 0x$x\n"
	#expect gdb { send_user "enable I/D cache done.\n" }
}


# Enable ILM
proc enable_ilm {} {
    send "set (long)\$milmb |= 0x1\n"
	expect gdb { send_user "enable ILM done.\n" }
}

# Enable DLM
proc enable_dlm {} {
	send "set (long)\$mdlmb |= 0x1\n"
	expect gdb { send_user "enable DLM done.\n" }

}

# Set hardware breakpoint in syscall entry point. (offset=8)
proc set_syscall_hardware_bk {} {
	set ir3 [expr [expr [ get_reg_value "ir3" ] & 0xc000 ] >> 14 ]
	set list "0x4 0x10 0x40 0x100"
	set syscall_value [expr [lindex $list $ir3] *8 ]

	send "hb *$syscall_value\n"
	expect gdb { send_user "set hw breakpoint in syscall.\n" }
}

# Check syscall is eqaul to 1 or not
proc check_syscall_value {} {
	global gdb_prompt_pattern

	set ir6 [expr [expr [ get_reg_value "ir6" ] & 0x7fff0000 ] >> 16 ]

	while { $ir6 != 1} {
		send "c\n"
		expect {
			-re "Breakpoint 1$gdb_prompt_pattern" {  }
			timeout { ctrlC }
		}
		set ir6 [expr [expr [ get_reg_value "ir6" ] & 0x7fff0000 ] >> 16 ]
	}
}

# Some cases of supertest need CVALSTDIN
proc STDIN {} {
	global stdin

	sleep 5
        set file [open $stdin]
        set inputs [split [read $file]]
        close $file
        foreach input $inputs {
        send "$input\n"
        }
}

# temporray workaround for current HVM design
proc setup_pma_for_hvm {} {
    send "set (long)\$pmacfg0 = 0xf\n"
	expect gdb { send_user "setup pmacfg0 done.\n" }

    send "set (long)\$pmaaddr0 = 0x2400ffff\n"
	expect gdb { send_user "setup pmaaddr0 done.\n" }
}

# set the DDR latency to 160 (40 + 20*6) cycles
proc setup_ddr_latency {} {
    send "set *0xf0100300=0x80000006L\n"
	expect gdb { send_user "setup DDR latency done.\n" }
}

# enable the non-blocking load
proc enable_non_blocking_load {} {
    send "set (long)\$mmisc_ctl |= 0x100L\n"
	expect gdb { send_user "enable mmisc_ctl.NBLD_EN done.\n" }
}

# setup the D$ write around threshold
proc setup_dc_write_around_threshold {} {
	global dc_wa_threshold

    set dc_wa_cfg_val [expr $dc_wa_threshold << 13]
    send "set (long)\$mcache_ctl |= $dc_wa_cfg_val\n"
    expect gdb { send_user "Setup the DC write around threshold done.\n" }
}

# ====== Start to test =====
# Check gdb status
expect {
	(gdb) {
		send_user "startup gdb Success\n"
	}
	timeout {
		send_user "startup gdb fail!\n"
		ctrlC
	}
}

# Set frame-arguments
send "set print frame-arguments none\n"
expect gdb { }

# Try to connect to target 10 times
for {set i 1} {$i <= 10} {incr i} {
	send "target remote $host:$port\n"
	expect {
	    -re "Remote communication error.  Target disconnected.: Connection reset by peer.$gdb_prompt_pattern$" {
		send_user "Connection reset by peer. Pausing, and trying again.\n"
		sleep 1
		continue
	    }
	    -re "Remote communication error.  Target disconnected.: Broken pipe.$gdb_prompt_pattern$" {
		send_user "Broken pipe. Pausing, and trying again.\n"
		sleep 1
		continue
	    }
